var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`전하께서 도착하셨다!`,JPN:`殿下のご到着だ！`,ENG:`His Royal Highness has arrived!`,TWN:`全員，列隊！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`전원, 도열!`,JPN:`全員、整列！`,ENG:`Troops, line up!`,TWN:`迎接殿下！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`들어라, 제국의 신민들이여!`,JPN:`聞け、帝国の臣民たちよ！`,ENG:`Hear me, subjects of the Empire!`,TWN:`帝國的百姓們，請聽我說！`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`오늘 그대들은 제국을 지키기 위해 여기 모인 것이 아니다!`,JPN:`今日は帝国を守るためにここに集まったのではない！`,ENG:`You are not gathered here today to protect the Empire!`,TWN:`今天你們聚集於此，不是為了保衛帝國！`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`센트럴 팰리스에서 그대들의 생환을 기도하고 있을 아내와 남편, 그리고 아들딸들을 위해!`,JPN:`セントラルパレスで各自の生還を祈っているであろう妻と夫、そして息子や娘のために！`,ENG:`You are here to protect your beloved spouse and children!`,TWN:`是為了在聖特羅貝里斯祈禱你們平安歸來的妻子、丈夫還有兒女們！`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`유린당한 여덟 대륙과 마지막으로 남은 이 땅을 되찾기 위해!`,JPN:`蹂躙された八つの大陸と最後に残ったこの地を取り戻すために！`,ENG:`To take back the eight lost continents and this very land that has been taken from us!`,TWN:`為了收復被踐踏的八塊大陸和最後僅存的這片土地！`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`나아가 저들이 속삭이는 멸망으로부터 우리의 내일을 지키기 위해!`,JPN:`ひいては、奴らの思惑である滅亡から我々の未来を守るために！`,ENG:`To protect the days of tomorrow, from the whispers of annihilation!`,TWN:`為了在毀滅的私語中守護我們的未來！`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그대들과 나는 여기 모인 것이다!`,JPN:`我らはこうしてここに集まったのだ！`,ENG:`That is why you and I are gathered here!`,TWN:`我和你們才會聚集於此！`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`저편에서 마왕의 군세가 다가오고 있다.`,JPN:`あの向こうでは魔王の軍勢が押し寄せてきている。`,ENG:`The forces of the Demon Lord approach us from far beyond.`,TWN:`那邊，魔王的軍隊正在逼近。`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`두려울 것이다. 어쩌면 도망치고 싶을지도 모르지.`,JPN:`恐ろしいだろう、逃げたくなるだろう。`,ENG:`Perhaps you are terrified. Perhaps you wish to run away.`,TWN:`你們會害怕，說不定還會想要逃跑。`},stage:{bg:`MS_1108`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`하지만 우리 모두 그들에게 점령된 땅을 이 두 눈으로 똑똑히 목격하지 않았던가?`,JPN:`だが、我々が全員が奴らに奪われた地がどうなったか、しかとその目で見てきたはずだ！`,ENG:`However, you have witnessed the land they conquered with our own eyes.`,TWN:`但是，我們親眼目睹了被他們佔領的土地是怎麼變成了廢墟！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`마왕은, 네헤모트는 점령자가 아니다!`,JPN:`魔王は、ネヘモトは征服者ではない！`,ENG:`Nehemoth, the Demon Lord, does not seek to conquer!`,TWN:`魔王，貝赫莫特不是征服者！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그는 우리에게 아무것도 원하지 않는다! 그저 이 세상에 아무것도 남기지 않으려 할 뿐!`,JPN:`奴は、我々に何かを望んでいるわけではない！　ただこの世からすべてを消し去ろうとしているだけだ！`,ENG:`He does not want anything from us! He merely seeks to destroy!`,TWN:`他不想從我們身上得到任何東西！他只是想讓這個世界燒成一塊焦土！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그러니 두렵다면 저 계곡 너머에 펼쳐진 황폐한 땅을 떠올려라.`,JPN:`だから、恐怖に負けそうになったら、あの渓谷の向こう側に広がっている荒廃した土地を思い出せ。`,ENG:`Should you be afraid, envision the barren wasteland beyond the creek.`,TWN:`所以，害怕的話，就想一想溪谷那頭的荒地。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`우리의 아내와 남편들에게.`,JPN:`我々の妻と夫に。`,ENG:`For it will be your only legacy if you choose to flee.`,TWN:`那是能夠留給你們妻子、你們丈夫，`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`훗날 새롭게 이 땅을 일굴 아들딸들에게.`,JPN:`そして将来この地を開拓していく子孫たちに。`,ENG:`To your wives and your husbands.`,TWN:`還有日後要新開墾這片土地的兒女們的唯一的東西！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}}];export{e as default};